import { createClient } from '@/lib/supabase/server';
import Link from 'next/link';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';

export default async function ProgramsPage() {
  const supabase = await createClient();
  const { data: { user } } = await supabase.auth.getUser();
  const { data: merchant } = await supabase.from('merchants').select('id').eq('user_id', user!.id).single();
  const { data: programs } = await supabase
    .from('loyalty_programs')
    .select('*')
    .eq('merchant_id', merchant!.id)
    .order('created_at', { ascending: false });

  return (
    <div>
      <div className="flex justify-between items-center mb-6">
        <h2 className="text-2xl font-bold">Loyalty Programs</h2>
        <Link href="/programs/new"><Button>Create Program</Button></Link>
      </div>
      {!programs?.length ? (
        <p className="text-gray-500">No programs yet. Create your first loyalty program!</p>
      ) : (
        <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
          {programs.map((p) => (
            <Link key={p.id} href={`/programs/${p.id}`}>
              <Card className="hover:shadow-md transition-shadow cursor-pointer">
                <CardHeader>
                  <div className="flex justify-between items-start">
                    <CardTitle className="text-lg">{p.name}</CardTitle>
                    <Badge variant={p.is_active ? 'default' : 'secondary'}>{p.is_active ? 'Active' : 'Inactive'}</Badge>
                  </div>
                </CardHeader>
                <CardContent>
                  <p className="text-sm text-gray-500 capitalize">{p.type} card</p>
                  {p.type === 'stamp' && <p className="text-sm">Goal: {p.stamp_goal} stamps</p>}
                  {p.type === 'points' && <p className="text-sm">{p.points_per_euro} pts/EUR</p>}
                  {p.expiration_days && <p className="text-sm text-gray-400">Expires in {p.expiration_days} days</p>}
                </CardContent>
              </Card>
            </Link>
          ))}
        </div>
      )}
    </div>
  );
}
