'use client';
import { useState } from 'react';
import { useRouter } from 'next/navigation';
import { createClient } from '@/lib/supabase/client';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Textarea } from '@/components/ui/textarea';

interface Props {
  programId: string;
  programType: 'stamp' | 'points';
}

export function RewardForm({ programId, programType }: Props) {
  const [name, setName] = useState('');
  const [description, setDescription] = useState('');
  const [discountType, setDiscountType] = useState('percentage');
  const [discountValue, setDiscountValue] = useState('');
  const [cost, setCost] = useState('');
  const [loading, setLoading] = useState(false);
  const router = useRouter();
  const supabase = createClient();

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    setLoading(true);
    await supabase.from('rewards').insert({
      program_id: programId,
      name,
      description: description || null,
      discount_type: discountType,
      discount_value: discountType === 'freebie' ? 0 : parseFloat(discountValue),
      points_cost: programType === 'points' ? parseInt(cost) : null,
      stamps_required: programType === 'stamp' ? parseInt(cost) : null,
    });
    router.refresh();
    setName(''); setDescription(''); setDiscountValue(''); setCost('');
    setLoading(false);
  }

  return (
    <form onSubmit={handleSubmit} className="space-y-3 p-4 border rounded-lg">
      <h3 className="font-semibold">Add Reward</h3>
      <div><Label>Name</Label><Input value={name} onChange={(e) => setName(e.target.value)} placeholder="e.g. Free Coffee" required /></div>
      <div><Label>Description</Label><Textarea value={description} onChange={(e) => setDescription(e.target.value)} /></div>
      <div>
        <Label>Discount Type</Label>
        <Select value={discountType} onValueChange={setDiscountType}>
          <SelectTrigger><SelectValue /></SelectTrigger>
          <SelectContent>
            <SelectItem value="percentage">Percentage off</SelectItem>
            <SelectItem value="fixed">Fixed amount off</SelectItem>
            <SelectItem value="freebie">Free item</SelectItem>
          </SelectContent>
        </Select>
      </div>
      {discountType !== 'freebie' && <div><Label>Discount Value {discountType === 'percentage' ? '(%)' : '(EUR)'}</Label><Input type="number" step="0.01" value={discountValue} onChange={(e) => setDiscountValue(e.target.value)} required /></div>}
      <div><Label>{programType === 'stamp' ? 'Stamps Required' : 'Points Cost'}</Label><Input type="number" value={cost} onChange={(e) => setCost(e.target.value)} required /></div>
      <Button type="submit" disabled={loading}>{loading ? 'Adding...' : 'Add Reward'}</Button>
    </form>
  );
}
