                  <div className="flex justify-between"><span className="font-medium">{r.name}</span><Badge>{r.discount_type}</Badge></div>
                  {r.description && <p className="text-sm text-gray-500 mt-1">{r.description}</p>}
                  <p className="text-sm mt-1">
                    {r.discount_type === 'freebie' ? 'Free item' : `${r.discount_value}${r.discount_type === 'percentage' ? '%' : ' EUR'} off`}
                    {' · '}
                    {program.type === 'stamp' ? `${r.stamps_required} stamps` : `${r.points_cost} points`}
                  </p>
                </div>
              ))}
            </div>
          )}
        </div>
        <RewardForm programId={id} programType={program.type} />
      </div>
    </div>
  );
}
