'use client';
import { useState } from 'react';
import { useRouter } from 'next/navigation';
import { createClient } from '@/lib/supabase/client';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { Textarea } from '@/components/ui/textarea';
import type { LoyaltyProgram } from '@loyalty/shared';

interface Props {
  merchantId: string;
  program?: LoyaltyProgram;
}

export function ProgramForm({ merchantId, program }: Props) {
  const [name, setName] = useState(program?.name ?? '');
  const [type, setType] = useState<string>(program?.type ?? 'stamp');
  const [stampGoal, setStampGoal] = useState(
    program?.stamp_goal?.toString() ?? '10'
  );
  const [pointsPerEuro, setPointsPerEuro] = useState(
    program?.points_per_euro?.toString() ?? '1'
  );
  const [rewardDescription, setRewardDescription] = useState(
    program?.reward_description ?? ''
  );
  const [expirationDays, setExpirationDays] = useState(
    program?.expiration_days?.toString() ?? ''
  );
  const [loading, setLoading] = useState(false);
  const router = useRouter();
  const supabase = createClient();

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    setLoading(true);
    const payload = {
      merchant_id: merchantId,
      name,
      type,
      stamp_goal: type === 'stamp' ? parseInt(stampGoal) : null,
      points_per_euro: type === 'points' ? parseFloat(pointsPerEuro) : null,
      reward_description: rewardDescription || null,
      expiration_days: expirationDays ? parseInt(expirationDays) : null,
    };

    if (program) {
      await supabase
        .from('loyalty_programs')
        .update(payload)
        .eq('id', program.id);
    } else {
      await supabase.from('loyalty_programs').insert(payload);
    }
    router.push('/programs');
    router.refresh();
  }

  return (
    <form onSubmit={handleSubmit} className="space-y-4 max-w-lg">
      <div>
        <Label>Program Name</Label>
        <Input
          value={name}
          onChange={(e) => setName(e.target.value)}
          placeholder="e.g. Coffee Stamp Card"
          required
        />
      </div>
      <div>
        <Label>Type</Label>
        <Select value={type} onValueChange={setType}>
          <SelectTrigger>
            <SelectValue />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="stamp">Stamp Card</SelectItem>
            <SelectItem value="points">Points System</SelectItem>
          </SelectContent>
        </Select>
      </div>
      {type === 'stamp' && (
        <div>
          <Label>Stamps to complete</Label>
          <Input
            type="number"
            value={stampGoal}
            onChange={(e) => setStampGoal(e.target.value)}
            min="1"
            required
          />
        </div>
      )}
      {type === 'points' && (
        <div>
          <Label>Points per EUR spent</Label>
          <Input
            type="number"
            step="0.1"
            value={pointsPerEuro}
            onChange={(e) => setPointsPerEuro(e.target.value)}
            min="0.1"
            required
          />
        </div>
      )}
      <div>
        <Label>Reward Description</Label>
        <Textarea
          value={rewardDescription}
          onChange={(e) => setRewardDescription(e.target.value)}
          placeholder="e.g. Free coffee after 10 stamps"
        />
      </div>
      <div>
        <Label>Expiration (days, optional)</Label>
        <Input
          type="number"
          value={expirationDays}
          onChange={(e) => setExpirationDays(e.target.value)}
          placeholder="Leave empty for no expiration"
        />
      </div>
      <Button type="submit" disabled={loading}>
        {loading ? 'Saving...' : program ? 'Update Program' : 'Create Program'}
      </Button>
    </form>
  );
}

